  getSettings: (): AppSettings => get(STORAGE_KEYS.SETTINGS, DEFAULT_SETTINGS),
  saveSettings: (data: AppSettings) => save(STORAGE_KEYS.SETTINGS, data),

  clearAll: () => {
    localStorage.clear();
