import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Transaction, Asset, Liability, Budget, SavingsGoal, AppSettings } from '../types';
import { StorageService } from '../services/storage';

interface FinanceContextType {
  transactions: Transaction[];
  assets: Asset[];
  liabilities: Liability[];
  budgets: Budget[];
  savingsGoals: SavingsGoal[];
  settings: AppSettings;
  loading: boolean;

  addTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addAsset: (a: Asset) => void;
  deleteAsset: (id: string) => void;
  addLiability: (l: Liability) => void;
  deleteLiability: (id: string) => void;

  addBudget: (b: Budget) => void;
  deleteBudget: (id: string) => void;
  addSavingsGoal: (g: SavingsGoal) => void;
  updateSavingsGoal: (g: SavingsGoal) => void;
  deleteSavingsGoal: (id: string) => void;

  updateSettings: (s: Partial<AppSettings>) => void;
  clearAllData: () => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider = ({ children }: { children: ReactNode }) => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [liabilities, setLiabilities] = useState<Liability[]>([]);
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [savingsGoals, setSavingsGoals] = useState<SavingsGoal[]>([]);
  const [settings, setSettings] = useState<AppSettings>(StorageService.getSettings());
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  useEffect(() => {
    const root = window.document.documentElement;
    if (settings.theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    StorageService.saveSettings(settings);
  }, [settings.theme]);

  const loadData = () => {
    try {
      setTransactions(StorageService.getTransactions());
      setAssets(StorageService.getAssets());
      setLiabilities(StorageService.getLiabilities());
      setBudgets(StorageService.getBudgets());
      setSavingsGoals(StorageService.getSavingsGoals());
      setSettings(StorageService.getSettings());
    } catch (e) {
      console.error("Failed to load data", e);
    } finally {
      setLoading(false);
    }
  };

  const addTransaction = (t: Transaction) => {
    const updated = [t, ...transactions];
    setTransactions(updated);
    StorageService.saveTransactions(updated);
  };
  const deleteTransaction = (id: string) => {
    const updated = transactions.filter(t => t.id !== id);
    setTransactions(updated);
    StorageService.saveTransactions(updated);
  };

  const addAsset = (a: Asset) => {
    const updated = [...assets, a];
    setAssets(updated);
    StorageService.saveAssets(updated);
  };
  const deleteAsset = (id: string) => {
    const updated = assets.filter(a => a.id !== id);
    setAssets(updated);
    StorageService.saveAssets(updated);
  };

  const addLiability = (l: Liability) => {
    const updated = [...liabilities, l];
    setLiabilities(updated);
    StorageService.saveLiabilities(updated);
  };
  const deleteLiability = (id: string) => {
    const updated = liabilities.filter(l => l.id !== id);
    setLiabilities(updated);
    StorageService.saveLiabilities(updated);
  };

  const addBudget = (b: Budget) => {
    const updated = [...budgets, b];
    setBudgets(updated);
    StorageService.saveBudgets(updated);
  };
  const deleteBudget = (id: string) => {
    const updated = budgets.filter(b => b.id !== id);
    setBudgets(updated);
    StorageService.saveBudgets(updated);
  };

  const addSavingsGoal = (g: SavingsGoal) => {
    const updated = [...savingsGoals, g];
    setSavingsGoals(updated);
    StorageService.saveSavingsGoals(updated);
  };
  const updateSavingsGoal = (g: SavingsGoal) => {
    const updated = savingsGoals.map(existing => existing.id === g.id ? g : existing);
    setSavingsGoals(updated);
    StorageService.saveSavingsGoals(updated);
  };
  const deleteSavingsGoal = (id: string) => {
    const updated = savingsGoals.filter(g => g.id !== id);
    setSavingsGoals(updated);
    StorageService.saveSavingsGoals(updated);
  };

  const updateSettings = (newSettings: Partial<AppSettings>) => {
    const updated = { ...settings, ...newSettings };
    setSettings(updated);
    StorageService.saveSettings(updated);
  };

  const clearAllData = () => {
    StorageService.clearAll();
    setTransactions([]);
    setAssets([]);
    setLiabilities([]);
    setBudgets([]);
    setSavingsGoals([]);
    setSettings({ currency: 'USD', theme: 'dark' });
  };

  return (
    <FinanceContext.Provider value={{
      transactions, assets, liabilities, budgets, savingsGoals, settings, loading,
      addTransaction, deleteTransaction,
      addAsset, deleteAsset,
      addLiability, deleteLiability,
      addBudget, deleteBudget,
      addSavingsGoal, updateSavingsGoal, deleteSavingsGoal,
      updateSettings, clearAllData
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import { Asset, Liability, Transaction, TransactionType, Budget } from '../types';

export const formatCurrency = (amount: number, currency: string = 'USD') => {
  if (currency === 'PKR') {
    return new Intl.NumberFormat('en-PK', {
        style: 'currency',
        currency: 'PKR',
        maximumFractionDigits: 0,
    }).format(amount);
  }
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(amount);
};

export const calculateNetWorth = (assets: Asset[], liabilities: Liability[]): number => {
  const totalAssets = assets.reduce((sum, item) => sum + item.value, 0);
  const totalLiabilities = liabilities.reduce((sum, item) => sum + item.balance, 0);
  return totalAssets - totalLiabilities;
};

export const calculateMonthlyCashFlow = (transactions: Transaction[]) => {
  const now = new Date();
  const currentMonthStr = now.toISOString().slice(0, 7); 

  const currentMonthTransactions = transactions.filter(t => t.date.startsWith(currentMonthStr));

  const income = currentMonthTransactions
    .filter(t => t.type === TransactionType.INCOME)
    .reduce((sum, t) => sum + t.amount, 0);

  const expenses = currentMonthTransactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .reduce((sum, t) => sum + t.amount, 0);

  return { income, expenses, net: income - expenses };
};

export const getSpendingByCategory = (transactions: Transaction[]) => {
  const categoryMap: Record<string, number> = {};

  transactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .forEach(t => {
      if (!categoryMap[t.category]) {
        categoryMap[t.category] = 0;
      }
      categoryMap[t.category] += t.amount;
    });

  return Object.entries(categoryMap)
    .map(([name, value]) => ({ name, value }))
    .sort((a, b) => b.value - a.value);
};

export const getMonthlyTrendData = (transactions: Transaction[]) => {
  const monthMap: Record<string, { income: number; expenses: number; savings: number }> = {};
  for (let i = 5; i >= 0; i--) {
    const d = new Date();
    d.setMonth(d.getMonth() - i);
    const key = d.toISOString().slice(0, 7); 
    monthMap[key] = { income: 0, expenses: 0, savings: 0 };
  }

  transactions.forEach(t => {
    const key = t.date.slice(0, 7);
    if (monthMap[key]) {
      if (t.type === TransactionType.INCOME) {
        monthMap[key].income += t.amount;
      } else if (t.type === TransactionType.EXPENSE) {
        monthMap[key].expenses += t.amount;
      }
    }
  });

  return Object.entries(monthMap).map(([date, data]) => ({
    name: new Date(date + '-01').toLocaleDateString('en-US', { month: 'short' }),
    income: data.income,
    expenses: data.expenses,
    savings: data.income - data.expenses
  }));
};

export const calculateBurnRate = (transactions: Transaction[]): number => {
    const trendData = getMonthlyTrendData(transactions);
    const recentMonths = trendData.slice(-3);
    const totalExpenses = recentMonths.reduce((sum, m) => sum + m.expenses, 0);
    return recentMonths.length ? totalExpenses / recentMonths.length : 0;
};

// New Helper for Budget Calculation
export const calculateBudgetUsage = (budget: Budget, transactions: Transaction[]) => {
    const now = new Date();
    let filtered = transactions.filter(t => t.type === TransactionType.EXPENSE);

    // Filter by Time Period
    if (budget.period === 'MONTHLY') {
        const currentMonth = now.toISOString().slice(0, 7);
        filtered = filtered.filter(t => t.date.startsWith(currentMonth));
    } else if (budget.period === 'YEARLY') {
        const currentYear = now.getFullYear().toString();
        filtered = filtered.filter(t => t.date.startsWith(currentYear));
    }

    // Filter by Category if needed
    if (budget.type === 'CATEGORY' && budget.category) {
        filtered = filtered.filter(t => t.category === budget.category);
    }

    const spent = filtered.reduce((sum, t) => sum + t.amount, 0);
    return {
        spent,
        remaining: budget.limit - spent,
        percentage: Math.min((spent / budget.limit) * 100, 100),
        isOverBudget: spent > budget.limit
    };
};

